# Sanitize and validate a regex pattern before compilation
# Prevents ReDoS and injection attacks
sub _sanitize_pattern {
    my ($self, $pattern) = @_;

    # Check for undef or empty
    unless (defined $pattern && length $pattern) {
        return (undef, "Pattern is empty or undefined");
    }

    # Enforce maximum length to prevent abuse
    if (length($pattern) > $self->{max_pattern_len}) {
        return (undef, "Pattern exceeds maximum allowed length of $self->{max_pattern_len}");
    }

    # Reject null bytes
    if ($pattern =~ /\0/) {
        return (undef, "Pattern contains null bytes");
    }

    # Reject patterns that attempt code execution via (?{ }) or (??{ })
    if ($pattern =~ /\(\s*\?{1,2}\s*\{/) {
        return (undef, "Pattern contains embedded code execution constructs (prohibited)");
    }

    # Reject patterns with excessive backtracking potential (basic ReDoS detection)
    # Detect nested quantifiers like (a+)+ or (a*)*
    if ($pattern =~ /(\(.+[*+]\s*\))\s*[*+]/) {
        return (undef, "Pattern contains nested quantifiers (potential ReDoS)");
    }

    # Detect (.+)+ or (.*)*  patterns
    if ($pattern =~ /\([^)]*[+*][^)]*\)[+*]/) {
        return (undef, "Pattern contains nested quantifiers (potential ReDoS)");
    }

    return ($pattern, undef);
}

# Safely compile a regex pattern
sub compile_pattern {
    my ($self, $name, $pattern, %opts) = @_;

    my $case_insensitive = $opts{case_insensitive} || 0;
    my $multiline        = $opts{multiline} || 0;
    my $anchor_full      = $opts{anchor_full} || 0;

    # Sanitize first
    my ($clean_pattern, $error) = $self->_sanitize_pattern($pattern);
    unless (defined $clean_pattern) {
        return (0, "Sanitization failed for pattern '$name': $error");
    }

    # Anchor the pattern to match the full string if requested
