        $clean_pattern = "\\A(?:$clean_pattern)\\z";
    }

    # Build modifier string
    my $modifiers = '';
    $modifiers .= 'i' if $case_insensitive;
    $modifiers .= 'm' if $multiline;

    # Compile using qr// inside eval for safety
