            # We use quotemeta-free approach but validate the pattern first
            if ($modifiers eq 'i') {
                $compiled = eval { qr/(?i)$clean_pattern/ };
            } elsif ($modifiers eq 'm') {
                $compiled = eval { qr/(?m)$clean_pattern/ };
            } elsif ($modifiers eq 'im' || $modifiers eq 'mi') {
                $compiled = eval { qr/(?im)$clean_pattern/ };
            } else {
                $compiled = eval { qr/$clean_pattern/ };
            }

            alarm(0);
        };
        alarm(0);  # Ensure alarm is cleared
    }

    if ($@ || !defined $compiled) {
        my $err = $@ || 'Unknown compilation error';
        chomp $err;
        return (0, "Failed to compile pattern '$name': $err");
    }

    # Store both original and compiled
    $self->{patterns}{$name} = {
        original => $pattern,
        sanitized => $clean_pattern,
        compiled  => $compiled,
        options   => \%opts,
    };
    $self->{compiled}{$name} = $compiled;

    return (1, undef);
}

# Load patterns from a configuration hash
sub load_config {
    my ($self, $config) = @_;

    unless (ref $config eq 'HASH') {
        croak "Configuration must be a hash reference";
    }

    my @errors;

    for my $name (sort keys %$config) {
        my $entry = $config->{$name};
        my ($pattern, %opts);

        if (ref $entry eq 'HASH') {
            $pattern = $entry->{pattern};
            %opts = map { $_ => $entry->{$_} }
                    grep { $_ ne 'pattern' } keys %$entry;
        } else {
            $pattern = $entry;
        }

        my ($ok, $error) = $self->compile_pattern($name, $pattern, %opts);
        unless ($ok) {
            push @errors, $error;
        }
    }

    return @errors ? (0, \@errors) : (1, undef);
}

# Validate a string against a named pattern
sub validate {
    my ($self, $name, $input) = @_;

    unless (exists $self->{compiled}{$name}) {
        return { valid => 0, error => "Unknown validation rule: '$name'" };
    }

    unless (defined $input) {
        return { valid => 0, error => "Input is undefined", rule => $name };
    }

    my $compiled = $self->{compiled}{$name};
    my $matched = 0;
    my @captures;

    # Use eval with timeout to prevent ReDoS at match time
    {
        local $SIG{ALRM} = sub { die "Pattern matching timed out\n" };
        eval {
            alarm($self->{timeout});
            if (@captures = ($input =~ $compiled)) {
                $matched = 1;
                # If no capture groups, @captures will be (1)
                @captures = () if (@captures == 1 && $captures[0] eq '1');
            }
            alarm(0);
        };
        alarm(0);
    }

    if ($@) {
        my $err = $@;
        chomp $err;
        return {
            valid    => 0,
            error    => "Matching error: $err",
            rule     => $name,
            input    => $input,
            timed_out => ($err =~ /timed out/) ? 1 : 0,
        };
    }

    return {
        valid    => $matched ? 1 : 0,
        rule     => $name,
        input    => $input,
        captures => \@captures,
        pattern  => "$compiled",
    };
}

# Validate input against multiple rules
sub validate_all {
    my ($self, $input, @rule_names) = @_;

    my @results;
    my $all_valid = 1;

    for my $name (@rule_names) {
        my $result = $self->validate($name, $input);
        push @results, $result;
        $all_valid = 0 unless $result->{valid};
    }

    return {
        all_valid => $all_valid,
        results   => \@results,
    };
}

# List all loaded patterns
sub list_patterns {
    my ($self) = @_;
    my %list;
    for my $name (sort keys %{$self->{patterns}}) {
        $list{$name} = {
            original => $self->{patterns}{$name}{original},
            compiled => "$self->{compiled}{$name}",
        };
    }
    return \%list;
}

# Remove a pattern
sub remove_pattern {
    my ($self, $name) = @_;
    delete $self->{patterns}{$name};
    delete $self->{compiled}{$name};
    return 1;
}

